params_path = 'exp8_csv_small/csv/urban_air_quality_sensors_1_1_params.json'
payload_path = 'exp8_csv_small/csv/urban_air_quality_sensors_1_1_payload.json'

def load(p):
    try:
        with open(p) as f:
            return json.load(f)
    except Exception:
        return {}

params_json = load(params_path)
payload_json = load(payload_path)

# Find hyper-parameter indices if present
hyper_index = None
total_hyper = None

def find_int(d, keys):
    if isinstance(d, dict):
        for k, v in d.items():
            lk = str(k).lower()
            for key in keys:
                if key in lk:
                    if isinstance(v, int):
                        return v
    return None

for d in (params_json, payload_json):
    if isinstance(d, dict):
        if hyper_index is None:
            hi = find_int(d, ['hyper_param_index', 'hyperparamindex'])
            if isinstance(hi, int): hyper_index = hi
        if total_hyper is None:
            th = find_int(d, ['total_hyper_params', 'totalhyperparams', 'total_hyperparam', 'totalparams'])
            if isinstance(th, int): total_hyper = th

# Collect names related to diurnal/anomaly/rows/sensors
def collect_keys(d, acc):
    if isinstance(d, dict):
        for k, v in d.items():
            lk = str(k).lower()
            if any(w in lk for w in ['diurnal','anomaly','row','sensor','pm','pm25','time','cycle','pattern','freq']):
                acc.add(str(k))
            collect_keys(v, acc)
    elif isinstance(d, list):
        for item in d:
            collect_keys(item, acc)

related = set()
collect_keys(params_json, related)
collect_keys(payload_json, related)

diurnal_names = sorted([n for n in related if 'diurnal' in n.lower()])
anomaly_names = sorted([n for n in related if 'anomaly' in n.lower()])
sensor_row_names = sorted([n for n in related if 'sensor' in n.lower() or 'row' in n.lower()])

# CSV stats: rows and sensors
row_count = 0
sensor_count = 0
try:
    with open(csv_path) as f:
        lines = f.readlines()
    if lines:
        header = lines[0].strip()
        row_count = len(lines) - 1
        cols = [c.strip() for c in header.split(',') if c.strip()]
        if cols:
            if cols[0].lower() in ('time','timestamp','date'):
                sensor_count = len(cols) - 1
            else:
                sensor_count = len(cols)
except Exception:
    pass

print('CSV path:', csv_path)
print('Hyper-parameter index used for this run:', hyper_index)
print('Total hyper-parameters configured for this run:', total_hyper)
print('Number of data rows in CSV (excluding header):', row_count)
print('Estimated number of sensors (data columns representing sensors):', sensor_count)

print('Diurnal-related parameter names surfaced in params/payload:', diurnal_names or ['None'])
print('Anomaly-related parameter names surfaced in params/payload:', anomaly_names or ['None'])
print('Sensor/row-related parameter names surfaced in params/payload:', sensor_row_names or ['None'])

if diurnal_names:
    print('Diurnal PM2.5 fluctuations are shaped by the parameter(s):', ', '.join(diurnal_names))
else:
    print('No explicit diurnal-shaping parameter surfaced by name in params/payload.')

if anomaly_names:
    print('Anomalies (frequency/size) are controlled by parameter(s):', ', '.join(anomaly_names))
else:
    print('No explicit anomaly-shaping parameter surfaced by name in params/payload.')

if row_count and sensor_count:
    print('The file contains', row_count, 'rows across', sensor_count, 'sensors.')
else:
    print('Could not determine exact row/sensor counts from the CSV.')

